{
  "nodes": [
    {
      "parameters": {
        "jsCode": "// Combine firstName and lastName into fullName for each item\nfor (const item of $input.all()) {\n  const first = item.json.firstName || '';\n  const last = item.json.lastName || '';\n  // Add the new fullName field to the existing JSON data\n  item.json.fullName = `${first} ${last}`.trim();\n}\n// Return all modified items\nreturn $input.all();"
      },
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [0, 0],
      "id": "GENERATED_UUID",
      "name": "Combine Names",
      "notes": "Combines the firstName and lastName fields from the input JSON into a new fullName field.",
      "credentials": {}
    }
  ],
  "connections": {}
}
